function cleanMarkdown(md = '') {
  return md
    // remove images
    .replace(/!\[[^\]]*\]\([^)]+\)/g, '')
    // convert links [text](url) => text
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
    // remove headings #
    .replace(/^#{1,6}\s*/gm, '')
    // remove table separator rows
    .replace(/^\|?\s*---.*$/gm, '')
    // replace table pipes
    .replace(/\|/g, ' ')
    // remove special arrows/symbols
    .replace(/[►→]/g, ' ')
    // remove extra spaces
    .replace(/[ \t]{2,}/g, ' ')
    // remove too many blank lines
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function shorten(text = '', max = 3000) {
  if (!text) return '';
  return text.length > max ? text.slice(0, max).trim() + '...' : text;
}

const input = $input.first().json;
const pages = input.data || [];

return pages.map((item, index) => {
  const meta = item.metadata || {};

  return {
    json: {
      success: input.success ?? null,
      status: input.status ?? null,
      completed: input.completed ?? 0,
      total: input.total ?? 0,
      creditsUsed: input.creditsUsed ?? 0,
      expiresAt: input.expiresAt ?? null,

      pageIndex: index + 1,
      url: meta.sourceURL || meta.url || null,
      title: meta.title || meta.ogTitle || meta['og:title'] || null,
      description: meta.description || meta.ogDescription || meta['og:description'] || null,
      summary: item.summary || null,
      cleanText: shorten(cleanMarkdown(item.markdown || ''), 5000)
    }
  };
});

function safeString(v) {
  return typeof v === 'string' ? v : '';
}

function decodeHtml(str) {
  return safeString(str)
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>');
}

function normalizeWhitespace(str) {
  return safeString(str)
    .replace(/\r/g, '')
    .replace(/\t/g, ' ')
    .replace(/\u00a0/g, ' ')
    .replace(/[ ]{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function cleanText(str) {
  let text = decodeHtml(str);

  // remove markdown images completely
  text = text.replace(/!\[[^\]]*]\((.*?)\)/g, ' ');

  // keep linked text, remove url
  text = text.replace(/\[([^\]]+)\]\((.*?)\)/g, '$1');

  // remove markdown symbols
  text = text.replace(/^[#>\-\*\+]+\s?/gm, '');
  text = text.replace(/[*_`~]+/g, '');

  return normalizeWhitespace(text);
}

function isNoiseLine(line) {
  const l = line.toLowerCase().trim();
  if (!l) return true;

  const badStarts = [
    'skip to',
    'search',
    'hello, sign in',
    'returns& orders',
    'sign in',
    'new customer?',
    'your account',
    'your lists',
    'all departments',
    'deliver to',
    'delivering to',
    'customer service',
    'amazon music',
    'best sellers',
    'today\'s deals',
    'registry',
    'prime',
    'cart',
    'orders',
    'home',
    'add to cart',
    'show/hide shortcuts',
    'keyboard shortcuts',
    'main content',
    'videos',
    'reviews',
    'compare with similar items',
    'buying options',
    'sponsored ad'
  ];

  if (badStarts.some(x => l === x || l.startsWith(x))) return true;
  if (/^[a-z]+(\+[a-z]+)*$/i.test(l)) return true;
  if (/^\d+$/.test(l)) return true;
  if (l.length < 3) return true;

  return false;
}

function splitLines(text) {
  return normalizeWhitespace(text)
    .split('\n')
    .map(x => x.trim())
    .filter(Boolean);
}

function extractBulletsFromSummary(summary) {
  const text = cleanText(summary);
  const lines = splitLines(text);

  const bullets = [];
  for (const line of lines) {
    if (isNoiseLine(line)) continue;

    if (
      line.length >= 20 &&
      line.length <= 300 &&
      !/[{}[\]|<>]/.test(line)
    ) {
      bullets.push(line);
    }
  }

  return [...new Set(bullets)].slice(0, 8);
}

function extractBulletsFromMarkdown(md) {
  const text = cleanText(md);
  const lines = splitLines(text);

  const bullets = [];
  for (const line of lines) {
    if (isNoiseLine(line)) continue;

    const looksUseful =
      line.length >= 20 &&
      line.length <= 260 &&
      !/^https?:\/\//i.test(line) &&
      !/[{}[\]|<>]/.test(line) &&
      !/^(all|account|registry|prime|music|fashion|books)$/i.test(line);

    if (looksUseful) bullets.push(line);
  }

  return [...new Set(bullets)].slice(0, 8);
}

function extractPrice(text) {
  const cleaned = safeString(text).replace(/,/g, '');
  const match = cleaned.match(/(?:\$|USD\s?)(\d+(?:\.\d{2})?)/i);
  return match ? `$${match[1]}` : null;
}

function chooseTitle(record) {
  const metadata = record.metadata || {};
  const candidates = [
    metadata.title,
    metadata["og:title"],
    record.title
  ]
    .map(safeString)
    .map(x => x.trim())
    .filter(Boolean);

  for (let title of candidates) {
    title = cleanText(title);

    title = title
      .replace(/\s*[|:-]\s*amazon\.com.*$/i, '')
      .replace(/\s*[|:-]\s*amazon.*$/i, '')
      .trim();

    if (title.length >= 8 && title.length <= 300) {
      return title;
    }
  }

  const text = cleanText(record.markdown || '');
  const lines = splitLines(text);
  for (const line of lines) {
    if (isNoiseLine(line)) continue;
    if (line.length >= 12 && line.length <= 220) {
      return line;
    }
  }

  return null;
}

function extractDescription(record, title) {
  const metadata = record.metadata || {};
  const candidates = [
    record.summary,
    metadata.description,
    metadata["og:description"],
    cleanText(record.markdown || '')
  ]
    .map(safeString)
    .map(cleanText)
    .filter(Boolean);

  for (let text of candidates) {
    text = text.replace(/\s+/g, ' ').trim();

    if (title) {
      const escaped = title.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      text = text.replace(new RegExp(`^${escaped}\\s*[.:\\-–—]*\\s*`, 'i'), '').trim();
    }

    if (text.length >= 40) {
      return text.slice(0, 700);
    }
  }

  return null;
}

function extractProduct(record, parent = {}) {
  const metadata = record.metadata || {};
  const markdown = safeString(record.markdown);
  const summary = safeString(record.summary);

  const title = chooseTitle(record);
  const bullets = [
    ...extractBulletsFromSummary(summary),
    ...extractBulletsFromMarkdown(markdown),
  ];

  const uniqueBullets = [...new Set(bullets)]
    .filter(x => !title || x.toLowerCase() !== title.toLowerCase())
    .slice(0, 6);

  const description = extractDescription(record, title);
  const price =
    extractPrice(markdown) ||
    extractPrice(summary) ||
    extractPrice(metadata.description || '');

  const url =
    metadata.sourceURL ||
    metadata.url ||
    record.url ||
    parent.url ||
    null;

  return {
    success: true,
    product: {
      title,
      description,
      bullets: uniqueBullets,
      price,
      url,
      source_url: metadata.sourceURL || null,
      marketplace: url && /amazon\./i.test(url) ? 'amazon' : null,
      content_type: metadata.contentType || parent.contentType || null,
      status_code: metadata.statusCode || parent.statusCode || null,
      cached_at: metadata.cachedAt || parent.cachedAt || null
    },
    raw: {
      summary: summary || null,
      metadata_title: metadata.title || null
    }
  };
}

const inputItems = $input.all();
const output = [];

for (const item of inputItems) {
  const root = item.json || {};
  const records = Array.isArray(root.data) ? root.data : [];

  for (const record of records) {
    const hasUsefulContent =
      record &&
      (record.markdown || record.summary || record.metadata?.title || record.metadata?.description);

    if (!hasUsefulContent) continue;

    const parsed = extractProduct(record, root);

    if (!parsed.product.title && !parsed.product.description) continue;

    output.push({ json: parsed });
  }
}

return output;
